import{_ as a,o as s,c as t,aA as n}from"./chunks/framework.CAIZw9CR.js";const u=JSON.parse('{"title":"Cookbook","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/first_steps/03_cookbook.md","filePath":"tutorials/first_steps/03_cookbook.md","lastUpdated":null}'),i={name:"tutorials/first_steps/03_cookbook.md"};function o(l,e,r,p,c,d){return s(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="Cookbook" tabindex="-1">Cookbook <a class="header-anchor" href="#Cookbook" aria-label="Permalink to &quot;Cookbook {#Cookbook}&quot;">​</a></h1><p>Copy-pasteable recipes for the most common <code>.krk</code> extensions. Each recipe is a minimal snippet plus a one-line explanation of what it does. Combine them to build richer simulations without reading the full <a href="./../../krk/overview">DSL reference</a>.</p><h2 id="Add-an-analytic-obstacle" tabindex="-1">Add an analytic obstacle <a class="header-anchor" href="#Add-an-analytic-obstacle" aria-label="Permalink to &quot;Add an analytic obstacle {#Add-an-analytic-obstacle}&quot;">​</a></h2><p>A cylinder at <code>(cx, cy)</code> with radius <code>R</code>:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Define cx = 2.5</span></span>
<span class="line"><span>Define cy = 1.25</span></span>
<span class="line"><span>Define R  = 0.5</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Obstacle cylinder { (x - cx)^2 + (y - cy)^2 &lt;= R^2 }</span></span></code></pre></div><p>Any expression returning a boolean on <code>(x, y)</code> works. A step: <code>{ x &lt; 1.0 &amp;&amp; y &gt; 0.5 }</code>. A triangle: <code>{ y &lt; x &amp;&amp; y &gt; -x &amp;&amp; x &lt; 1.0 }</code>. See <a href="/lauguimel.github.io/Kraken.jl/dev/krk/directives#obstacle-fluid">Obstacle / Fluid</a> for the full grammar.</p><h2 id="Load-an-STL-body" tabindex="-1">Load an STL body <a class="header-anchor" href="#Load-an-STL-body" aria-label="Permalink to &quot;Load an STL body {#Load-an-STL-body}&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Obstacle wing stl(file = &quot;assets/wing.stl&quot;, scale = 1e-3, translate = [1.0, 0.5, 0.0])</span></span></code></pre></div><ul><li><p><code>scale</code> multiplies all vertex coordinates before insertion.</p></li><li><p><code>translate</code> shifts the body after scaling.</p></li><li><p>STL files are rasterised onto the grid at simulation init.</p></li></ul><h2 id="Set-a-parabolic-inlet" tabindex="-1">Set a parabolic inlet <a class="header-anchor" href="#Set-a-parabolic-inlet" aria-label="Permalink to &quot;Set a parabolic inlet {#Set-a-parabolic-inlet}&quot;">​</a></h2><p>Replace the inlet <code>Boundary</code> with a spatial expression:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Define U = 0.05</span></span>
<span class="line"><span>Define H = 1.0</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Boundary west velocity(ux = 4*U*y*(H - y)/H^2, uy = 0)</span></span></code></pre></div><p>The expression uses the DSL&#39;s spatial variables <code>x</code>, <code>y</code>, <code>z</code>, <code>t</code> and standard math functions (<code>sin</code>, <code>cos</code>, <code>exp</code>, <code>sqrt</code>, …). See <a href="./../../krk/expressions">Expressions</a>.</p><h2 id="Turn-on-thermal-coupling" tabindex="-1">Turn on thermal coupling <a class="header-anchor" href="#Turn-on-thermal-coupling" aria-label="Permalink to &quot;Turn on thermal coupling {#Turn-on-thermal-coupling}&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Module thermal</span></span>
<span class="line"><span>Physics nu = 0.01  Pr = 0.71  Ra = 1e5</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Boundary south wall T = 1.0</span></span>
<span class="line"><span>Boundary north wall T = 0.0</span></span>
<span class="line"><span>Boundary x     periodic</span></span></code></pre></div><p><code>Module thermal</code> enables the temperature DDF and unlocks the <code>T = ...</code> kwarg on <code>wall</code> boundaries. Scalar T only in v0.1.0 — a spatial temperature profile on a wall is on the roadmap.</p><h2 id="Start-from-a-preset,-override-a-few-bits" tabindex="-1">Start from a preset, override a few bits <a class="header-anchor" href="#Start-from-a-preset,-override-a-few-bits" aria-label="Permalink to &quot;Start from a preset, override a few bits {#Start-from-a-preset,-override-a-few-bits}&quot;">​</a></h2><p>Presets expand into canonical directive stacks. Run Rayleigh-Bénard at a different Rayleigh number without rewriting the domain:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Preset rayleigh_benard_2d</span></span>
<span class="line"><span>Physics nu = 0.005  Pr = 0.71  Ra = 1e6</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Run 50000 steps</span></span>
<span class="line"><span>Output vtk every 5000 [rho, ux, uy, T]</span></span></code></pre></div><p>Later directives override earlier ones (so <code>Physics</code> and <code>Run</code> here replace what the preset wrote). The five presets are <code>cavity_2d</code>, <code>poiseuille_2d</code>, <code>couette_2d</code>, <code>taylor_green_2d</code>, <code>rayleigh_benard_2d</code>.</p><h2 id="Drive-flow-with-a-body-force" tabindex="-1">Drive flow with a body force <a class="header-anchor" href="#Drive-flow-with-a-body-force" aria-label="Permalink to &quot;Drive flow with a body force {#Drive-flow-with-a-body-force}&quot;">​</a></h2><p>Useful for periodic channels and natural convection side-cases:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Physics nu = 0.1  Fx = 1e-5</span></span>
<span class="line"><span>Physics nu = 0.1  Fx = 0  Fy = -9.81*beta*(T - T_ref)</span></span></code></pre></div><p><code>Fx</code>, <code>Fy</code>, <code>Fz</code> accept any expression — constants, functions of <code>(x, y, T, …)</code>, etc.</p><h2 id="Parser-only:-grid-refinement-patch" tabindex="-1">Parser-only: grid refinement patch <a class="header-anchor" href="#Parser-only:-grid-refinement-patch" aria-label="Permalink to &quot;Parser-only: grid refinement patch {#Parser-only:-grid-refinement-patch}&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Refine nearwall { region = [0.0, 0.0, 1.0, 0.1], ratio = 2 }</span></span>
<span class="line"><span>Refine tip      { region = [0.4, 0.0, 0.6, 0.1], ratio = 2, parent = nearwall }</span></span></code></pre></div><p><code>region = [x0, y0, x1, y1]</code> is axis-aligned. <code>ratio = 2</code> doubles resolution; <code>parent</code> chains nested levels. In this branch the parser accepts the directive, but <code>run_simulation</code> rejects refinement at runtime. Treat this syntax as reserved for the development branch.</p><h2 id="Initial-condition-with-an-expression" tabindex="-1">Initial condition with an expression <a class="header-anchor" href="#Initial-condition-with-an-expression" aria-label="Permalink to &quot;Initial condition with an expression {#Initial-condition-with-an-expression}&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Initial { ux = 0.05*sin(2*pi*x) uy = -0.05*cos(2*pi*y) T = 0.5 }</span></span></code></pre></div><p>Fields not listed inherit their zero/uniform default.</p><h2 id="Log-diagnostics-during-the-run" tabindex="-1">Log diagnostics during the run <a class="header-anchor" href="#Log-diagnostics-during-the-run" aria-label="Permalink to &quot;Log diagnostics during the run {#Log-diagnostics-during-the-run}&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Diagnostics every 100 [step, time, KE, uMax, drag, lift]</span></span></code></pre></div><p>Writes a CSV next to the VTK outputs. Column names must match the runner&#39;s registered diagnostics — see <a href="./../../api/postprocess">Postprocess</a>.</p><h2 id="Use-dimensionless-helpers" tabindex="-1">Use dimensionless helpers <a class="header-anchor" href="#Use-dimensionless-helpers" aria-label="Permalink to &quot;Use dimensionless helpers {#Use-dimensionless-helpers}&quot;">​</a></h2><p>Instead of hand-picking <code>nu</code>, express the setup physically:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Setup reynolds = 1000  L_ref = 1.0  U_ref = 0.1</span></span></code></pre></div><p>Kraken back-computes <code>nu = U_ref * L_ref / reynolds</code>. For thermal:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Setup rayleigh = 1e5  prandtl = 0.71  L_ref = 1.0</span></span></code></pre></div><p>Yields <code>nu</code>, <code>alpha</code>, <code>gbeta_DT</code> consistent with the requested Ra-Pr. See <a href="./../../krk/helpers">Helpers</a> for the formulas.</p><h2 id="Sanity-check-before-running" tabindex="-1">Sanity-check before running <a class="header-anchor" href="#Sanity-check-before-running" aria-label="Permalink to &quot;Sanity-check before running {#Sanity-check-before-running}&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kraken</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> info</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> examples/cavity.krk</span></span></code></pre></div><p>Prints the fully-resolved setup and flags <code>τ &lt; 0.55</code> (instability) or <code>Mach &gt; 0.1</code> (incompressibility breakdown). Cheaper than discovering the issue after 60 000 steps.</p><h2 id="Run-a-parameter-sweep" tabindex="-1">Run a parameter sweep <a class="header-anchor" href="#Run-a-parameter-sweep" aria-label="Permalink to &quot;Run a parameter sweep {#Run-a-parameter-sweep}&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Sweep nu = [0.1, 0.05, 0.02, 0.01]</span></span></code></pre></div><p>One full simulation per value. Outputs go to <code>output/&lt;name&gt;_nu=&lt;value&gt;/</code>. Combine with <code>Diagnostics</code> to build convergence curves automatically.</p><h2 id="Overriding-from-the-CLI" tabindex="-1">Overriding from the CLI <a class="header-anchor" href="#Overriding-from-the-CLI" aria-label="Permalink to &quot;Overriding from the CLI {#Overriding-from-the-CLI}&quot;">​</a></h2><p>Any <code>Physics</code> scalar (and <code>Nx</code>, <code>Ny</code>, <code>max_steps</code>, …) is overridable at launch:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kraken</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> examples/cavity.krk</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --nu=0.01</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --Nx=256</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --max_steps=100000</span></span></code></pre></div><p>Takes precedence over the file&#39;s values without editing the file.</p><hr><p>Need a recipe that isn&#39;t here? Open the <a href="./../../krk/overview">.krk DSL reference</a> for the exhaustive syntax, or check the <a href="./../../examples/01_poiseuille_2d">Examples</a> for full-worked simulations.</p>`,51)])])}const b=a(i,[["render",o]]);export{u as __pageData,b as default};
